def build_moce(m,s):
 sid=m["source_id"];t=base(m,"Nine MgO-supported Fe/Mo/Ce catalyst compositions from Tables 1-2, each retained as a distinct CVD run.")
 recs=(("FE100",100,0,0,"10.9","0.09","Yes","212"),("MO100",0,100,0,"12.2","0.78","No","not_reported"),("CE100",0,0,100,"10.3","0.92","No","not_reported"),("CE10",90,0,10,"14.2","0.10","Yes","188"),("CE50",50,0,50,"13.6","0.20","Yes","188"),("CE90",10,0,90,"13.6","0.81","Yes","188"),("MO10",90,10,0,"18.8","0.11","Yes","212"),("MO50",50,50,0,"30.3","0.17","Yes","212"),("MO90",10,90,0,"15.9","0.40","Yes","212"))
 for code,fe,mo,ce,mg,dg,rbm,peak in recs:
  rid=f"{sid}_{code}";metals="; ".join(x for x,v in (("Fe",fe),("Mo",mo),("Ce",ce)) if v);out=f"{mg} mg graphitic carbon; D/G {dg}; RBM {rbm}";t["source_run"].append(run_row(sid,code,f"Fe/Mo/Ce {fe}/{mo}/{ce} on MgO",out))
  t["catalyst_system"].append(catalyst_row(rid,catalyst_label=f"{code} on MgO",active_metals=metals,support_material="MgO nanopowder",metal_ratio_original=f"Fe/Mo/Ce={fe}/{mo}/{ce}; total metal 28 mol% vs MgO",precursor_summary="Fe(NO3)3·9H2O; (NH4)2MoO4; Ce(NO3)3·6H2O as applicable",preparation_method="incipient-water slurry impregnation",preparation_detail="grind salts with MgO; minimal DI water; stir 20 min; ultrasonicate 10 min; dry 80 C overnight"))
  t["reactor_process_gas"].append(process_row(rid,1,"methane_CVD",reactor_type="25.4 mm alumina work tube furnace",temperature_setpoint_C="900",holding_time_min="30",carbon_source="CH4",carbon_source_flow_original="200 cm3/min",carbon_source_flow_sccm="200",inert_gas="Ar",inert_gas_flow_original="400 cm3/min heat-up/cool-down",inert_gas_flow_sccm="400",process_note="0.1 g catalyst; heat at 30 C/min under Ar; switch to methane at 900 C."))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="graphitic carbon mass",yield_original=f"{mg} mg",yield_value_standardized=mg,yield_unit_standardized="mg graphitic carbon per 0.1 g catalyst batch",yield_definition_original="TGA high-temperature carbon burn-off; microscopy/RBM indicate close approximation to CNT mass",secondary_result_summary=out,CNT_type_reported="SWCNT" if rbm=="Yes" else "graphitic carbon with no clear SWCNT RBM",CNT_type_confirmed="SWCNT" if rbm=="Yes" else "not_confirmed",product_mixture_summary=out,CNT_type_evidence="TEM/SEM plus Raman RBM",RBM_peak_reported=peak,Raman_ratio_type="ID/IG",Raman_ratio_value=dg,characterization_methods="TEM; SEM; Raman; TGA"))
  t["cost_scale_review"].append(cost_row(rid,scale_evidence_summary="0.1 g catalyst laboratory tube-CVD batch.",cost_driver_summary="MgO and nitrate/molybdate salts, 900 C furnace, methane and argon.",safety_risk="Methane at 900 C; Fe/Mo/Ce salts and CNT powder.",emission_or_waste="Methane CVD exhaust and acid-soluble MgO/metal catalyst residue."));ev(t,s,sid,rid,"SPAN_0B1B6BB849C79BC86523","SPAN_D61A043B2380678F8640","SPAN_0B1B6BB849C79BC86523")
 return t

