  t["catalyst_system"].append(catalyst_row(rid,catalyst_label="3 nm Fe / 5 nm Al patterned catalyst",active_metals="Fe",support_material="5 nm Al buffer on 10 x 10 mm Si",metal_ratio_original="3 nm Fe over 5 nm Al",preparation_method="photolithography plus electron-beam evaporation",preparation_detail=f"10 micrometre circular catalyst patterns in {arr} arrangement at {pitch} micrometre pitch"))
