def build_purification(m,s):
 sid=m["source_id"];t=base(m,"Four Co:Mo:MgO catalyst preparation/loading combinations with linked methane-CVD and HCl purification outcomes.")
 recs=(("IMP_5_10","impregnation","5:10:85","88","8.1"),("SG_5_10","sol-gel","5:10:85","85","9.0"),("IMP_5_20","impregnation","5:20:75","68","not_reported"),("SG_5_20","sol-gel","5:20:75","81","not_reported"))
 for code,method,ratio,yld,diam in recs:
  rid=f"{sid}_{code}";out=f"carbon yield {yld}%; MWNT diameter 3-20 nm";t["source_run"].append(run_row(sid,code,f"CoMo/MgO {ratio} by {method}",out))
