  t["catalyst_system"].append(catalyst_row(rid,catalyst_label=f"CoMo/MgO {ratio} {method}",active_metals="Co; Mo",support_material="MgO",metal_ratio_original=f"Co:Mo:MgO={ratio} by weight",precursor_summary="Co(NO3)2·6H2O; (NH4)6Mo7O24·4H2O; MgO or Mg(NO3)2·6H2O",preparation_method=method,preparation_detail=prep,activation_condition="H2 150 mL/min to 500 C"))
  t["reactor_process_gas"].append(process_row(rid,1,"fluidized_bed_methane_CVD",reactor_type="vertical fluidized-bed reactor",temperature_setpoint_C="800",holding_time_min="30",carbon_source="CH4",carbon_source_flow_original="150 mL/min",carbon_source_flow_sccm="150",reducing_gas="H2",reducing_gas_flow_original="150 mL/min to 500 C",reducing_gas_flow_sccm="150",inert_gas="N2",inert_gas_flow_original="150 mL/min during 500-800 C ramp and cooling",inert_gas_flow_sccm="150",process_note="1 g catalyst; 10 C/min ramp. Purification: 0.4 g CNT in 100 mL 0.3 M HCl, agitate 2 h, sonicate 30 min, agitate 2 h, age 8 h, filter/wash, dry 120 C 12 h."))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="carbon yield",yield_original=f"{yld}%",yield_value_standardized=yld,yield_unit_standardized="wt.% carbon",yield_definition_original="TGA-derived carbon yield of as-produced product",secondary_result_summary=out,CNT_type_reported="multi-walled carbon nanotubes",CNT_type_confirmed="MWCNT",product_mixture_summary="low-amorphous-carbon MWNT plus MgO/Co/Mo catalyst before purification",CNT_type_evidence="TEM and single 550-590 C TPO oxidation peak",outer_diameter_mean_nm=diam,outer_diameter_range_nm="3-20",morphology="well-structured MWNT; more bamboo-like defects at 20 wt% Mo",characterization_methods="SEM; TEM; EDX; XRD; XPS; Raman; TGA/TPO",post_treatment_or_purification="mild HCl purification",purification_condition="0.3 M HCl sequence; complete MgO removal but partial Co/Mo residue"))
  t["cost_scale_review"].append(cost_row(rid,scale_evidence_summary="1 g catalyst fluidized-bed batch; 0.4 g aliquot purification.",cost_driver_summary="Catalyst preparation, 800 C fluidized bed, methane/H2/N2 and multi-hour dilute-HCl purification.",safety_risk="Hydrogen/methane at 800 C, HCl and Co/Mo/CNT powders.",emission_or_waste="CVD exhaust and acidic Mg/Co/Mo-containing purification liquor."));ev(t,s,sid,rid,"SPAN_618F8E0243C639874DE1","SPAN_618F8E0243C639874DE1","SPAN_1421583CCFFEE8B9E352")
