def build_continuous(m,s):
 sid=m["source_id"];t=base(m,"Two Fe-aerosol cooling experiments and one sequential Fe-to-Co aerosol experiment resolving continuous catalyst feeding.")
 recs=(("FE_STD","2.5 wt% ferrocene/toluene, standard ~2 h furnace cooling","850","15","~925 micrometre VACNT carpet; Fe ~3.7 wt% at top and ~1.5 wt% through much of carpet"),("FE_QUENCH","2.5 wt% ferrocene/toluene, rapid furnace-movement quench","850","15","~790 micrometre VACNT carpet; numerous external nanoparticles; Fe ~6.5 wt% at top and 2-2.5 wt% through carpet"),("FE_CO_SEQ","ferrocene followed by cobaltocene sequential aerosol","800","not_reported","bilayer aligned VACNT carpet: 100 micrometre top + 15 micrometre bottom; Fe/Co mixed catalyst segments"))
 for code,prec,temp,time,out in recs:
  rid=f"{sid}_{code}";t["source_run"].append(run_row(sid,code,prec,out))
  t["catalyst_system"].append(catalyst_row(rid,catalyst_label=prec,active_metals="Fe" if code!="FE_CO_SEQ" else "Fe; Co",support_material="quartz reactor substrate/base-growth surface",precursor_summary=prec,preparation_method="aerosolized metallocene/toluene continuous feed",preparation_detail="solution nebulized and carried in Ar through a 200 C evaporator",phase_or_state_summary="gas-phase-nucleated nanoparticles continuously feed root catalyst particles"))
  t["reactor_process_gas"].append(process_row(rid,1,"aerosol_assisted_CCVD",reactor_type="45 cm tubular furnace with quartz reactor at atmospheric pressure",temperature_setpoint_C=temp,holding_time_min=time,pressure_original="atmospheric",pressure_kPa="101.325",carbon_source="toluene",cofeed_or_reactive_gas="ferrocene aerosol" if code!="FE_CO_SEQ" else "ferrocene aerosol followed by cobaltocene aerosol",inert_gas="Ar",process_note="No enhancer; aerosol evaporator 200 C. "+("Rapid quench after synthesis." if code=="FE_QUENCH" else "Standard furnace-inertia cooling." if code=="FE_STD" else "Sequential precursor switch.")))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="VACNT carpet structure/metal profile",yield_original=out,yield_definition_original="SEM/WDS/TEM-EELS outcome; no mass yield",secondary_result_summary=out,CNT_type_reported="vertically aligned carbon nanotubes",CNT_type_confirmed="VACNT",product_mixture_summary=out,CNT_type_evidence="SEM; TEM/STEM-EELS; WDS; Raman",length_summary="~925 micrometres" if code=="FE_STD" else "~790 micrometres" if code=="FE_QUENCH" else "115 micrometres total",morphology="aligned carpet" if code!="FE_CO_SEQ" else "two aligned layers with disordered top region",alignment_or_array="vertically aligned carpet",characterization_methods="SEM; TEM; STEM-EELS; WDS; Raman"))
  t["cost_scale_review"].append(cost_row(rid,scale_evidence_summary="15 min laboratory aerosol-CCVD carpet for Fe cooling comparison; sequential study at laboratory furnace scale.",cost_driver_summary="Metallocene/toluene aerosol, argon, 800-850 C furnace and electron microscopy/elemental profiling.",safety_risk="Toluene/metallocene aerosol at high temperature; air-sensitive cobaltocene and CNT aerosol.",emission_or_waste="Organic/metal aerosol exhaust and metal-containing VACNT material."));ev(t,s,sid,rid,"SPAN_37F24C9FD7D970F5D9DD","SPAN_37F24C9FD7D970F5D9DD","SPAN_0BD131B00F66D2F810EC" if code=="FE_CO_SEQ" else "SPAN_37F24C9FD7D970F5D9DD")
 return t

def build_thesis(m,s):
 sid=m["source_id"];t=base(m,"Four thesis experiments/series: ethanol trial, productive methanol/hexane base recipe, water-addition series and Gd-salt trial.")
 recs=(("ETHANOL","ethanol/ferrocene/thiophene","1150","ethanol; ferrocene 0.5-2 g/100 mL; thiophene 0.3 g/100 mL","No large CNT assembly; black amorphous-carbon coating with some CNT fibers","SPAN_2D968186C8020368AA71"),("BASE","90 vol% methanol + 10 vol% n-hexane; 0.5% thiophene; 0.5-2% ferrocene","1200","base spinnable recipe","large quantity of CNT films/cylindrical sock; typical fuel 0.8 mL/min and Ar 500-2500 sccm","SPAN_677EC9E4EA5D5589098F"),("WATER","base recipe + 1-5 vol% water","1200","water concentration series","1-4 vol% water generated thinner/more transparent CNT cylinder; 5% failed","SPAN_517E65A5AEF0964665DE"),("GD","base recipe + GdCl3·6H2O","1200","0.4-0.5 ferrocene; 0.3 thiophene; final condition included Gd additive","thin/continuous sock at final 200 sccm Ar condition; material felt more resilient","SPAN_352E51A80DFDF4B2C343"))
 for code,label,temp,feed,out,span in recs:
  rid=f"{sid}_{code}";r=run_row(sid,code,label,out,"medium" if code in ("WATER","GD") else "high");r["data_type"]="experimental_series_summary" if code in ("WATER","GD") else "experimental_run";t["source_run"].append(r)
  t["catalyst_system"].append(catalyst_row(rid,catalyst_label="ferrocene floating Fe catalyst"+(" with GdCl3·6H2O" if code=="GD" else ""),active_metals="Fe; Gd" if code=="GD" else "Fe",support_material="floating/no solid support",precursor_summary=feed,preparation_method="liquid injection floating-catalyst CVD",preparation_detail="ferrocene carbon/catalyst provider; thiophene sulfur promoter"))
  t["reactor_process_gas"].append(process_row(rid,1,"floating_catalyst_CVD",reactor_type="multi-field quartz/alumina-tube reactor",temperature_setpoint_C=temp,carbon_source="ethanol" if code=="ETHANOL" else "methanol/n-hexane 9:1",carbon_source_flow_original="0.8 mL/min typical" if code!="ETHANOL" else "not_reported",inert_gas="Ar",inert_gas_flow_original="~500 sccm" if code=="ETHANOL" else "500-2500 sccm typical" if code=="BASE" else "condition series; 200 sccm in final Gd run" if code=="GD" else "not individually reported",cofeed_or_reactive_gas="thiophene promoter; "+("water 1-5 vol%" if code=="WATER" else "GdCl3·6H2O" if code=="GD" else "none beyond recipe"),process_note=feed))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="spinnable CNT assembly formation",yield_original=out,yield_definition_original="Observed sock/cylinder/fiber production; no mass yield",secondary_result_summary=out,CNT_type_reported="CNT fiber/film; base recipe intended mostly DWCNT",CNT_type_confirmed="CNT assembly" if code!="ETHANOL" else "limited CNT fibers",product_mixture_summary=out,CNT_type_evidence="visual collection plus later Raman/TEM characterization",morphology="continuous cylindrical sock/fiber" if code!="ETHANOL" else "amorphous wall coating with sparse fibers",characterization_methods="visual process observation; Raman; SEM/TEM in thesis characterization chapter",application_property_summary="water/alcohol densification and direct spinning at ~50 rpm when Ar ~1000 sccm" if code=="BASE" else out))
  t["cost_scale_review"].append(cost_row(rid,scale_evidence_summary="Continuous laboratory floating-catalyst reactor producing collectable yarn/sheet precursor where successful.",cost_driver_summary="1200 C reactor, methanol/hexane/ferrocene/thiophene feed, argon and continuous collection.",safety_risk="Flammable alcohol/hexane, thiophene, ferrocene/Gd salt and CNT aerosol at 1150-1200 C.",emission_or_waste="Organic/metal-containing reactor exhaust, amorphous carbon and CNT offcuts."));ev(t,s,sid,rid,span,span,span)
 return t

BUILDERS:dict[str,Callable]={"LIT_9D1D16C5D2C154FD":build_moce,"LIT_A2AD11A61964181A":build_emitters,"LIT_A51E66EB3D1E73F8":build_purification,"LIT_A5F937C1E53DFE57":build_continuous,"LIT_A72F77DDF27B1E9C":build_thesis}
def main():
 md=load_metadata("B");s=EvidenceStore();ms=[]
 try:
  for sid in SOURCE_IDS:
   metric=existing_package_metric(sid,"B")
   if metric is None:ms.append(publish_package(sid,BUILDERS[sid](md[sid],s)))
   else:ms.append(metric)
 finally:s.close()
 result={"batch_id":BATCH_NAME,"sources":ms,"total_runs":sum(x["row_counts"]["source_run"] for x in ms),"status":"completed_needs_review"};(REPORT_ROOT/"manual_batch_019_metrics.json").write_text(json.dumps(result,ensure_ascii=False,indent=2)+"\n",encoding="utf-8");print(json.dumps(result,ensure_ascii=False,indent=2))
if __name__=="__main__":main()
